import java.util.Scanner;

public class SafeBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine(); // Use nextLine() to allow spaces in input

        // Validate input length to prevent buffer overflow
        if (input.length() > 10) {
            System.out.println("Input exceeds maximum allowed length.");
            return; // Exit the program if input is too long
        }

        byte[] buffer = new byte[10];
        System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());

        System.out.println("Hello, " + new String(buffer).trim()); // Trim any extra bytes from buffer
    }
}

### Explanation:
취약유형: Buffer Overflow
